function [imgOut,cnt] = fXrayOutV10(img,prm)%% low pass filter%% [img,cntX] = fXrayOutV010(img,prm)% img:      input image% prm:      1x4 array, [fct,pit,minX,itr]% fct:      factor to take out the point% pit:      depth of the pit% minX:     minimun counts to be taken% itr:      number of iteration%% imgOut:      input image% cnt:     counts that taken out from image%% Kei Nakamura% Created on Thursday, March 9th 2006.% Modified on Friday, August 21st 2009.% Modified on Thursday, February 17th 2011.%% ver.5: impliment minimum counts% ver.6: edge problem% ver.7: edge problem (v6 cut too much)% ver.8: limited number of iteration% ver.9: make simpler% ver.10: make simpler% ver.10a: negative factor%% input and initializationfct = prm(1);pit = prm(2);minX = prm(3);itr = prm(4);cnt = sum(sum(img));%% make padded imageedgT = img(1:pit,:);                % edge top for virtual imageedgB = img(end-pit+1:end,:);        % edge for bottomedgL = img(:,1:pit);                % edge leftedgR = img(:,end-pit+1:end);        % edge rightcrn = zeros(pit,pit);               % cornerpdImg = [crn,edgT,crn;edgL,img,edgR;crn,edgB,crn];    % image+pad%% allocation[szy,szx] = size(img);imgOut = img;   % copyimgRfT = zeros(szy,szx); imgRfB = zeros(szy,szx);imgRfL = zeros(szy,szx); imgRfR = zeros(szy,szx);imgRf = zeros(szy,szx); imgX = zeros(szy,szx);%% main loopif fct>0    for sss=1:itr        %% make averaged image        imgRfT(:,:) = 0.25*pdImg(1:end-2*pit,1+pit:end-pit);    % top reference/4        imgRfB(:,:) = 0.25*pdImg(1+2*pit:end,1+pit:end-pit);    % bottom reference/4        imgRfL(:,:) = 0.25*pdImg(1+pit:end-pit,1:end-2*pit);    % left reference/4        imgRfR(:,:) = 0.25*pdImg(1+pit:end-pit,1+2*pit:end);    % right reference/4        imgRf(:,:) = imgRfT + imgRfB + imgRfL + imgRfR;       % averaged reference        %% replace to average if logic is on          imgX(:,:) = (imgOut - fct*imgRf)>0 & img>=minX; % logic for pixels to be replaced        imgOut(:,:) = imgOut.*(~imgX)+imgRf.*imgX;           %         %% update padded image        edgT(:,:) = imgOut(1:pit,:);                % edge top for virtual image        edgB(:,:) = imgOut(end-pit+1:end,:);        % edge for bottom        edgL(:,:) = imgOut(:,1:pit);                % edge left        edgR(:,:) = imgOut(:,end-pit+1:end);        % edge right        pdImg(:,:) = [crn,edgT,crn;edgL,imgOut,edgR;crn,edgB,crn];    % update padded image    endelseif fct<0    for sss=1:itr            %% make averaged image        imgRfT(:,:) = 0.25*pdImg(1:end-2*pit,1+pit:end-pit);    % top reference/4        imgRfB(:,:) = 0.25*pdImg(1+2*pit:end,1+pit:end-pit);    % bottom reference/4        imgRfL(:,:) = 0.25*pdImg(1+pit:end-pit,1:end-2*pit);    % left reference/4        imgRfR(:,:) = 0.25*pdImg(1+pit:end-pit,1+2*pit:end);    % right reference/4        imgRf(:,:) = imgRfT + imgRfB + imgRfL + imgRfR;       % averaged reference        %% replace to average if logic is on          imgX(:,:) = (imgOut*fct + imgRf)>0 & img>=minX; % logic for pixels to be replaced        imgOut(:,:) = imgOut.*(~imgX)+imgRf.*imgX;           %         %% update padded image        edgT(:,:) = imgOut(1:pit,:);                % edge top for virtual image        edgB(:,:) = imgOut(end-pit+1:end,:);        % edge for bottom        edgL(:,:) = imgOut(:,1:pit);                % edge left        edgR(:,:) = imgOut(:,end-pit+1:end);        % edge right        pdImg(:,:) = [crn,edgT,crn;edgL,imgOut,edgR;crn,edgB,crn];    % update padded image    endendcnt = cnt - sum(sum(imgOut));
